29	#[derive(Clone, Debug)]
30	pub struct AssignTargetInfo {
31	    pub ty: Type,
32	    pub kind: AssignTargetKind,
33	}
34	
35	#[derive(Clone, Debug, PartialEq, Eq)]
36	pub enum AssignTargetKind {
37	    Local,
38	    Storage,
39	    ExternalStorage,
40	    Err,
41	}
42	
43	impl TypeCheckingVisitor<'_> {
44	    /// Returns information about an expression when used as the LHS of an assignment.
45	    ///
46	    /// Specifically, this function returns an `AssignTargetInfo` containing:
47	    /// - the type of the expression (`ty`),
48	    /// - the kind of assignment target (`Local`, `Storage`, `ExternalStorage`, or `Err`).
49	    ///
50	    /// Supported LHS expressions include:
51	    /// - `Path` (variables),
52	    /// - `ArrayAccess`,
53	    /// - `MemberAccess`,
54	    /// - `TupleAccess`.
55	    ///
56	    /// This function also performs static checks for:
57	    /// - invalid assignment targets (anything other than the supported LHS expressions),
58	    /// - assignments to external records or tuples in disallowed scopes,
59	    /// - reassignment of `Future` or `Mapping` types,
60	    ///
61	    /// It also updates the type table with the expression’s type.
62	    pub fn visit_expression_assign(&mut self, input: &Expression) -> AssignTargetInfo {
63	        let assign_target_info = match input {
64	            Expression::ArrayAccess(array_access) => AssignTargetInfo {
65	                ty: self.visit_array_access_general(array_access, true, &None),
66	                kind: AssignTargetKind::Local,
67	            },
68	            Expression::Path(path) if path.qualifier().is_empty() => self.visit_path_assign(path),
69	            Expression::MemberAccess(member_access) => AssignTargetInfo {
70	                ty: self.visit_member_access_general(member_access, true, &None),
71	                kind: AssignTargetKind::Local,
72	            },
73	            Expression::TupleAccess(tuple_access) => AssignTargetInfo {
74	                ty: self.visit_tuple_access_general(tuple_access, true, &None),
75	                kind: AssignTargetKind::Local,
76	            },
77	            _ => {
78	                self.emit_err(TypeCheckerError::invalid_assignment_target(input, input.span()));
79	                AssignTargetInfo { ty: Type::Err, kind: AssignTargetKind::Err }
80	            }
81	        };
82	
83	        // Check external record assignment
84	        if let Expression::Path(path) = input
85	            && !self.symbol_in_conditional_scope(path.identifier().name)
86	            && (self.is_external_record(&assign_target_info.ty)
87	                || matches!(&assign_target_info.ty, Type::Tuple(tuple) if tuple.elements().iter().any(|ty| self.is_external_record(ty))))
88	        {
89	            if self.is_external_record(&assign_target_info.ty) {
90	                self.emit_err(TypeCheckerError::assignment_to_external_record_cond(
91	                    &assign_target_info.ty,
92	                    input.span(),
93	                ));
94	            } else {
95	                // Note that this will cover both assigning to a tuple variable and assigning to a member of a tuple.
96	                self.emit_err(TypeCheckerError::assignment_to_external_record_tuple_cond(
97	                    &assign_target_info.ty,
98	                    input.span(),
99	                ));
100	            }
101	        }
102	
103	        // Prohibit reassignment of futures or mappings
104	        match &assign_target_info.ty {
105	            Type::Future(..) => self.emit_err(TypeCheckerError::cannot_reassign_final_variable(input, input.span())),
106	            Type::Mapping(_) => self.emit_err(TypeCheckerError::cannot_reassign_mapping(input, input.span())),
107	            _ => {}
108	        }
109	
110	        // Add the expression and its associated type to the type table.
111	        self.state.type_table.insert(input.id(), assign_target_info.ty.clone());
112	        assign_target_info
113	    }
114	
115	    pub fn visit_array_access_general(&mut self, input: &ArrayAccess, assign: bool, expected: &Option<Type>) -> Type {
116	        // Check that the expression is an array.
117	        let this_type = if assign {
118	            self.visit_expression_assign(&input.array).ty
119	        } else {
120	            self.visit_expression(&input.array, &None)
121	        };
122	        self.assert_array_type(&this_type, input.array.span());
123	
124	        // Check that the index is an integer type.
125	        let mut index_type = self.visit_expression(&input.index, &None);
126	
127	        if index_type == Type::Numeric {
128	            // If the index has type `Numeric`, then it's an unsuffixed literal. Just infer its type to be `u32` and
129	            // then check it's validity as a `u32`.
130	            index_type = Type::Integer(IntegerType::U32);
131	            if let Expression::Literal(literal) = &input.index {
132	                self.check_numeric_literal(literal, &index_type);
133	            }
134	        }
135	
136	        self.assert_int_type(&index_type, input.index.span());
137	
138	        // Keep track of the type of the index in the type table.
139	        // This is important for when the index is an unsuffixed literal.
140	        self.state.type_table.insert(input.index.id(), index_type.clone());
141	
142	        // Get the element type of the array.
143	        let Type::Array(array_type) = this_type else {
144	            // We must have already reported an error above, in our type assertion.
145	            return Type::Err;
146	        };
147	
148	        let element_type = array_type.element_type();
149	
150	        // If the expected type is known, then check that the element type is the same as the expected type.
151	        self.maybe_assert_type(element_type, expected, input.span());
152	
153	        // Return the element type of the array.
154	        element_type.clone()
155	    }
156	
157	    pub fn visit_member_access_general(&mut self, input: &MemberAccess, assign: bool, expected: &Option<Type>) -> Type {
158	        let ty = if assign {
159	            self.visit_expression_assign(&input.inner).ty
160	        } else {
161	            self.visit_expression(&input.inner, &None)
162	        };
163	
164	        // Make sure we're not assigning to a member of an external record.
165	        if assign && self.is_external_record(&ty) {
166	            self.emit_err(TypeCheckerError::assignment_to_external_record_member(&ty, input.span));
167	        }
168	
169	        // Check that the type of `inner` in `inner.name` is a composite.
170	        match ty {
171	            Type::Err => Type::Err,
172	            Type::Composite(ref composite) => {
173	                // Retrieve the composite definition associated with `identifier`.
174	                let Some(composite) = self.lookup_composite(composite.path.expect_global_location()) else {
175	                    self.emit_err(TypeCheckerError::undefined_type(ty, input.inner.span()));
176	                    return Type::Err;
177	                };
178	                // Check that `input.name` is a member of the composite.
179	                match composite.members.iter().find(|member| member.name() == input.name.name) {
180	                    // Case where `input.name` is a member of the composite.
181	                    Some(Member { type_, .. }) => {
182	                        // Check that the type of `input.name` is the same as `expected`.
183	                        self.maybe_assert_type(type_, expected, input.span());
184	                        type_.clone()
185	                    }
186	                    // Case where `input.name` is not a member of the composite.
187	                    None => {
188	                        self.emit_err(TypeCheckerError::invalid_composite_variable(
189	                            input.name,
190	                            &composite,
191	                            input.name.span(),
192	                        ));
193	                        Type::Err
194	                    }
195	                }
196	            }
197	            Type::DynRecord => {
198	                if assign {
199	                    self.emit_err(TypeCheckerError::type_should_be2(
200	                        "dyn record",
201	                        "an assignable struct or record",
202	                        input.inner.span(),
203	                    ));
204	                    return Type::Err;
205	                }
206	                // `.owner` is always accessible and returns `address`.
207	                if input.name.name == sym::owner {
208	                    self.maybe_assert_type(&Type::Address, expected, input.span());
209	                    Type::Address
210	                } else if let Some(expected_type) = expected {
211	                    // Other fields require a type annotation (via `let x: T = r.field` or `r.field as T`).
212	                    expected_type.clone()
213	                } else {
214	                    self.emit_err(TypeCheckerError::dyn_record_field_requires_type(input.name, input.name.span()));
215	                    Type::Err
216	                }
217	            }
218	            type_ => {
219	                self.emit_err(TypeCheckerError::type_should_be2(type_, "a struct or record", input.inner.span()));
220	                Type::Err

