49	/// Finds a base port where `count` consecutive ports are all available.
50	fn find_free_port_range(count: u16) -> u16 {
51	    for _ in 0..100 {
52	        let base = find_free_port();
53	        let all_free = (1..count).all(|offset| std::net::TcpListener::bind(("127.0.0.1", base + offset)).is_ok());
54	        if all_free {
55	            return base;
56	        }
57	    }
