122	/// CLI tests start only after the devnode is fully initialized.
123	fn wait_for_devnode(port: u16) {
124	    let height_url = format!("http://127.0.0.1:{port}/testnet/block/height/latest");
125	    let start = std::time::Instant::now();
126	    let timeout = std::time::Duration::from_secs(300);
